CREATE   PROC [dbo].[TR_GUIMAIL_DANHSACH_YEUCAUXUATKHO](@ngaythang date)
AS
BEGIN
	DECLARE @currentDate datetime;
	SET @currentDate = @ngaythang;

	DECLARE @currentHour int = DATEPART(HH, GETDATE());
	DECLARE @currentMinute int = DATEPART(MI, GETDATE());

	SET @currentDate = DATEADD(MI, @currentMinute, DATEADD(HH, @currentHour, @currentDate));

	DECLARE @currentTime time(0) = CAST(@currentDate AS time(0));
	DECLARE @beginTime time(0) = DATEADD(HOUR, -2, @currentTime)

	DECLARE @htmString TABLE
	(
		stt int IDENTITY(1, 1),
		body nvarchar(max)
	)

	IF EXISTS (SELECT 1 FROM tr_phieuyeucau A WHERE CAST(ngaytao AS date) = @ngaythang AND CONVERT(time(0), A.ngaytao) BETWEEN @beginTime AND @currentTime)
	BEGIN
		INSERT INTO @htmString(body)
		VALUES (N'<table width=100% border=1 cellSpacing=0 cellPadding=2>'),
			   (N'<tr>'),
			   (N'<th colSpan=9>Ngày: ' + FORMAT(@ngaythang, 'dd/MM/yyyy') + '</th>'), 
			   (N'</tr>'),

			   (N'<tr>'),
			   (N'<th>Số phiếu</th>'), 
			   (N'<th>Kho</th>'), 
			   (N'<th>Mã chi tiết</th>'), 
			   (N'<th>Mô tả</th>'), 
			   (N'<th>Màu sắc</th>'),
			   (N'<th>Quy cách</th>'),
			   (N'<th>Số lượng</th>'),
			   (N'<th>Ngày cập nhật</th>'),
			   (N'<th>Người cập nhật</th>'),
			   (N'</tr>'),
			   (N'<tbody>')

		DECLARE @sophieu1 int = 0;
		DECLARE @sophieu int, @tenkho nvarchar(max), @mucdich nvarchar(max);
		DECLARE @mact nvarchar(200), @mota nvarchar(max), @mausac nvarchar(200), @quycach nvarchar(200), @soluong float, @ngaytao datetime, @nguoitao nvarchar(200);

		DECLARE CUR CURSOR LOCAL FOR
			SELECT A.sophieu, D.[description] AS tenkho, A.mucdich,
				B.mact, C.mota, C.mausac, C.quycach, B.soluong, A.ngaytao, E.FullName AS nguoitao
			FROM tr_phieuyeucau A 
				INNER JOIN tr_phieuyeucau_chitiet B ON A.id = B.phieuyeucau_id
				INNER JOIN tr_material C ON B.mact = C.mavt
				LEFT JOIN tr_site D ON A.makho = D.name
				LEFT JOIN SYS_USER E ON A.nguoitao = E.UserName
			WHERE A.active = 1 AND B.active = 1 AND A.IsFinish = 0 AND A.BGD_CANCEL = 0
				AND CAST(A.ngaytao AS date) = @ngaythang 
				AND CONVERT(time(0), A.ngaytao) BETWEEN @beginTime AND @currentTime
				AND ISNULL(A.nguoiky, '') = ''
			ORDER BY A.sophieu
		OPEN CUR
		FETCH NEXT FROM CUR INTO @sophieu, @tenkho, @mucdich, @mact, @mota, @mausac, @quycach, @soluong, @ngaytao, @nguoitao;
		WHILE @@FETCH_STATUS = 0
		BEGIN
			DECLARE @row nvarchar(max) = '';
			IF @sophieu1 <> @sophieu
			BEGIN
				SET @row = N'<tr>';
				SET @row = @row + FORMATMESSAGE(N'<td colSpan=9 style=''font-weight: bold''>Số phiếu: %s.<br>Mục đích sử dụng: %s</td>', CONVERT(nvarchar(50), @sophieu), @mucdich);
				SET @row = @row + N'</tr>';

				--SET @row = @row + N'<tr>';
				--SET @row = @row + FORMATMESSAGE(N'<td colSpan=9>Mục đích sử dụng: %s</td>',  @mucdich);
				--SET @row = @row + N'</tr>';
				INSERT INTO @htmString(body) VALUES (@row);

				SET @sophieu1 = @sophieu;
			END

			SET @row = N'<tr>'
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', CONVERT(nvarchar(50), @sophieu));
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', @tenkho);
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', @mact);
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', @mota);
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', @mausac);
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', @quycach);
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', FORMAT(@soluong, '#,0.##'));
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', FORMAT(@ngaytao, 'HH:mm:ss'));
			SET @row = @row + FORMATMESSAGE(N'<td>%s</td>', @nguoitao);
			SET @row = @row + N'</tr>'

			INSERT INTO @htmString(body) VALUES (@row);

			FETCH NEXT FROM CUR INTO @sophieu, @tenkho, @mucdich, @mact, @mota, @mausac, @quycach, @soluong, @ngaytao, @nguoitao;
		END
		CLOSE CUR;
		DEALLOCATE CUR;

		INSERT INTO @htmString(body) VALUES (N'</tbody>'), (N'</table>')
	
	END
	SELECT * FROM @htmString ORDER BY stt
END
